  1→import { useCallback } from 'react';
  2→import { View, Text, StyleSheet, ScrollView, FlatList, RefreshControl, Pressable } from 'react-native';
  3→import { useRouter } from 'expo-router';
  4→import { SafeAreaView } from 'react-native-safe-area-context';
  5→import { useAuth } from '@/contexts/AuthContext';
  6→import { useCachedQuery } from '@/hooks/useCachedQuery';
  7→import { supabase } from '@/lib/supabase';
  8→import { LoyaltyCardMobile } from '@/components/cards/LoyaltyCardMobile';
  9→import { OfflineBanner } from '@/components/ui/OfflineBanner';
 10→import { SkeletonCard } from '@/components/ui/Skeleton';
 11→import { EmptyState } from '@/components/ui/EmptyState';
 12→import { Badge } from '@/components/ui/Badge';
 13→import theme from '@/theme';
 14→import type { LoyaltyCard, Reward, Scan } from '@astrolab/shared';
 15→
 16→export default function Dashboard() {
 17→  const router = useRouter();
 18→  const { profile } = useAuth();
 19→
 20→  const { data: cards, loading: cardsLoading, refresh: refreshCards } = useCachedQuery<LoyaltyCard[]>(
 21→    'dashboard_cards',
 22→    async () => {
 23→      const { data, error } = await supabase
 24→        .from('loyalty_cards')
 25→        .select('*, merchants(name, logo_url, business_type, loyalty_type, stamps_required, points_per_euro, reward_threshold)')
 26→        .order('updated_at', { ascending: false })
 27→        .limit(10);
 28→      if (error) throw error;
 29→      return (data as unknown as LoyaltyCard[]) ?? [];
 30→    },
 31→    []
 32→  );
 33→
 34→  const { data: rewards, refresh: refreshRewards } = useCachedQuery<Reward[]>(
 35→    'dashboard_rewards',
 36→    async () => {
 37→      const { data, error } = await supabase
 38→        .from('rewards')
 39→        .select('*')
 40→        .eq('is_redeemed', false)
 41→        .order('created_at', { ascending: false })
 42→        .limit(5);
 43→      if (error) throw error;
 44→      return (data as Reward[]) ?? [];
 45→    },
 46→    []
 47→  );
 48→
 49→  const { data: recentScans, refresh: refreshScans } = useCachedQuery<Scan[]>(
 50→    'dashboard_scans',
 51→    async () => {
 52→      const { data, error } = await supabase
 53→        .from('scans')
 54→        .select('*, merchants(name)')
 55→        .order('created_at', { ascending: false })
 56→        .limit(5);
 57→      if (error) throw error;
 58→      return (data as unknown as Scan[]) ?? [];
 59→    },
 60→    []
 61→  );
 62→
 63→  const onRefresh = useCallback(() => {
 64→    refreshCards();
 65→    refreshRewards();
 66→    refreshScans();
 67→  }, []);
 68→
 69→  const totalCards = cards?.length ?? 0;
 70→  const pendingRewards = rewards?.length ?? 0;
 71→  const totalScans = recentScans?.length ?? 0;
 72→
 73→  return (
 74→    <SafeAreaView style={styles.container} edges={['top']}>
 75→      <OfflineBanner />
 76→      <ScrollView
 77→        refreshControl={<RefreshControl refreshing={false} onRefresh={onRefresh} tintColor={theme.colors.primary} />}
 78→        contentContainerStyle={styles.scrollContent}
 79→      >
 80→        {/* Header */}
 81→        <View style={styles.header}>
 82→          <View>
 83→            <Text style={styles.greeting}>
 84→              Bonjour {profile?.full_name?.split(' ')[0] ?? ''} 👋
 85→            </Text>
 86→            <Text style={styles.subGreeting}>Votre fidelite en un coup d'oeil</Text>
 87→          </View>
 88→        </View>
 89→
 90→        {/* Stats row */}
 91→        <View style={styles.statsRow}>
 92→          {[
 93→            { label: 'Cartes', value: totalCards, emoji: '💳' },
 94→            { label: 'Recompenses', value: pendingRewards, emoji: '🎁' },
 95→            { label: 'Scans', value: totalScans, emoji: '📱' },
 96→          ].map((stat) => (
 97→            <View key={stat.label} style={styles.statCard}>
 98→              <Text style={styles.statEmoji}>{stat.emoji}</Text>
 99→              <Text style={styles.statValue}>{stat.value}</Text>
100→              <Text style={styles.statLabel}>{stat.label}</Text>
101→            </View>
102→          ))}
103→        </View>
104→
105→        {/* Cards horizontal */}
106→        <View style={styles.section}>
107→          <View style={styles.sectionHeader}>
108→            <Text style={styles.sectionTitle}>Mes cartes</Text>
109→            <Pressable onPress={() => router.push('/(tabs)/cards')}>
110→              <Text style={styles.seeAll}>Voir tout →</Text>
111→            </Pressable>
112→          </View>
113→          {cardsLoading ? (
114→            <View style={{ flexDirection: 'row', gap: 12 }}>
115→              <SkeletonCard />
116→              <SkeletonCard />
117→            </View>
118→          ) : !cards?.length ? (
119→            <EmptyState
120→              icon="💳"
121→              title="Aucune carte"
122→              description="Scannez un QR code en magasin pour obtenir votre premiere carte."
123→            />
124→          ) : (
125→            <FlatList
126→              data={cards}
127→              horizontal
128→              showsHorizontalScrollIndicator={false}
129→              keyExtractor={(item) => item.id}
130→              contentContainerStyle={{ gap: 12 }}
131→              renderItem={({ item }) => (
132→                <Pressable onPress={() => router.push(`/(tabs)/cards/${item.id}`)}>
133→                  <LoyaltyCardMobile card={item} />
134→                </Pressable>
135→              )}
136→            />
137→          )}
138→        </View>
139→
140→        {/* Pending rewards */}
141→        {pendingRewards > 0 && (
142→          <View style={styles.section}>
143→            <Text style={styles.sectionTitle}>Recompenses a recuperer 🎉</Text>
144→            {rewards?.map((reward) => (
145→              <View key={reward.id} style={styles.rewardItem}>
146→                <View style={{ flex: 1 }}>
147→                  <Text style={styles.rewardText}>{reward.description}</Text>
148→                  <Text style={styles.rewardDate}>
149→                    {new Date(reward.created_at).toLocaleDateString('fr-FR')}
150→                  </Text>
151→                </View>
152→                <Badge variant="success">A recuperer</Badge>
153→              </View>
154→            ))}
155→          </View>
156→        )}
157→
158→        {/* Recent activity */}
159→        <View style={styles.section}>
160→          <Text style={styles.sectionTitle}>Activite recente</Text>
161→          {!recentScans?.length ? (
162→            <Text style={styles.emptyText}>Aucune activite recente</Text>
163→          ) : (
164→            recentScans.map((scan) => (
165→              <View key={scan.id} style={styles.activityItem}>
166→                <Text style={styles.activityEmoji}>📱</Text>
167→                <View style={{ flex: 1 }}>
168→                  <Text style={styles.activityText}>
169→                    {(scan as any).merchants?.name ?? 'Magasin'}
170→                  </Text>
171→                  <Text style={styles.activityDetail}>
172→                    {scan.stamps_added ? `+${scan.stamps_added} tampon(s)` : ''}
173→                    {scan.points_added ? `+${scan.points_added} pts` : ''}
174→                  </Text>
175→                </View>
176→                <Text style={styles.activityDate}>
177→                  {new Date(scan.created_at).toLocaleDateString('fr-FR')}
178→                </Text>
179→              </View>
180→            ))
181→          )}
182→        </View>
183→      </ScrollView>
184→    </SafeAreaView>
185→  );
186→}
187→
188→const styles = StyleSheet.create({
189→  container: { flex: 1, backgroundColor: theme.colors.background },
190→  scrollContent: { paddingBottom: 100 },
191→  header: { paddingHorizontal: theme.spacing.lg, paddingTop: theme.spacing.md, paddingBottom: theme.spacing.lg },
192→  greeting: { fontSize: theme.fontSize['2xl'], fontWeight: '700', color: theme.colors.text },
193→  subGreeting: { fontSize: theme.fontSize.sm, color: theme.colors.textMuted, marginTop: 2 },
