195→  statCard: { flex: 1, backgroundColor: theme.colors.surface, borderRadius: theme.borderRadius.lg, padding: theme.spacing.md, alignItems: 'center', ...theme.shadow },
196→  statEmoji: { fontSize: 24, marginBottom: 4 },
197→  statValue: { fontSize: theme.fontSize.xl, fontWeight: '700', color: theme.colors.text },
198→  statLabel: { fontSize: theme.fontSize.xs, color: theme.colors.textMuted },
199→  section: { paddingHorizontal: theme.spacing.lg, marginBottom: theme.spacing.lg },
200→  sectionHeader: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', marginBottom: theme.spacing.sm },
201→  sectionTitle: { fontSize: theme.fontSize.lg, fontWeight: '600', color: theme.colors.text },
202→  seeAll: { fontSize: theme.fontSize.sm, color: theme.colors.primary, fontWeight: '500' },
203→  rewardItem: { flexDirection: 'row', alignItems: 'center', backgroundColor: theme.colors.surface, borderRadius: theme.borderRadius.md, padding: theme.spacing.md, marginTop: theme.spacing.sm, ...theme.shadow },
204→  rewardText: { fontSize: theme.fontSize.sm, fontWeight: '500', color: theme.colors.text },
205→  rewardDate: { fontSize: theme.fontSize.xs, color: theme.colors.textMuted, marginTop: 2 },
206→  emptyText: { fontSize: theme.fontSize.sm, color: theme.colors.textMuted, textAlign: 'center', paddingVertical: theme.spacing.lg },
207→  activityItem: { flexDirection: 'row', alignItems: 'center', gap: theme.spacing.sm, paddingVertical: theme.spacing.sm, borderBottomWidth: 1, borderBottomColor: theme.colors.border },
208→  activityEmoji: { fontSize: 20 },
209→  activityText: { fontSize: theme.fontSize.sm, fontWeight: '500', color: theme.colors.text },
210→  activityDetail: { fontSize: theme.fontSize.xs, color: theme.colors.primary },
211→  activityDate: { fontSize: theme.fontSize.xs, color: theme.colors.textMuted },
212→});
