  1→import { View, Text, StyleSheet, ScrollView, RefreshControl } from 'react-native';
  2→import { useLocalSearchParams, Stack } from 'expo-router';
  3→import { SafeAreaView } from 'react-native-safe-area-context';
  4→import QRCode from 'react-native-qrcode-svg';
  5→import { useCachedQuery } from '@/hooks/useCachedQuery';
  6→import { useBrightness } from '@/hooks/useBrightness';
  7→import { useAuth } from '@/contexts/AuthContext';
  8→import { supabase } from '@/lib/supabase';
  9→import { CircularProgress } from '@/components/cards/CircularProgress';
 10→import { StampsGridMobile } from '@/components/cards/StampsGridMobile';
 11→import { Card } from '@/components/ui/Card';
 12→import { Badge } from '@/components/ui/Badge';
 13→import { SkeletonCard } from '@/components/ui/Skeleton';
 14→import theme from '@/theme';
 15→import type { LoyaltyCard, Scan, Reward } from '@astrolab/shared';
 16→
 17→export default function CardDetailScreen() {
 18→  const { cardId } = useLocalSearchParams<{ cardId: string }>();
 19→  const { user } = useAuth();
 20→
 21→  // Maximize brightness for QR display
 22→  useBrightness(true);
 23→
 24→  const { data: card, loading, refresh } = useCachedQuery<LoyaltyCard | null>(
 25→    `card_${cardId}`,
 26→    async () => {
 27→      const { data, error } = await supabase
 28→        .from('loyalty_cards')
 29→        .select('*, merchants(name, logo_url, business_type, loyalty_type, stamps_required, points_per_euro, reward_threshold)')
 30→        .eq('id', cardId)
 31→        .single();
 32→      if (error) throw error;
 33→      return data as unknown as LoyaltyCard;
 34→    },
 35→    [cardId]
 36→  );
 37→
 38→  const { data: scans } = useCachedQuery<Scan[]>(
 39→    `card_scans_${cardId}`,
 40→    async () => {
 41→      if (!card) return [];
 42→      const { data, error } = await supabase
 43→        .from('scans')
 44→        .select('*')
 45→        .eq('merchant_id', card.merchant_id)
 46→        .order('created_at', { ascending: false })
 47→        .limit(10);
 48→      if (error) throw error;
 49→      return (data as Scan[]) ?? [];
 50→    },
 51→    [card?.merchant_id]
 52→  );
 53→
 54→  const { data: rewards } = useCachedQuery<Reward[]>(
 55→    `card_rewards_${cardId}`,
 56→    async () => {
 57→      if (!card) return [];
 58→      const { data, error } = await supabase
 59→        .from('rewards')
 60→        .select('*')
 61→        .eq('merchant_id', card.merchant_id)
 62→        .order('created_at', { ascending: false })
 63→        .limit(5);
 64→      if (error) throw error;
 65→      return (data as Reward[]) ?? [];
 66→    },
 67→    [card?.merchant_id]
 68→  );
 69→
 70→  const merchant = (card as any)?.merchants;
 71→  const isStamps = card?.card_type === 'stamps' || merchant?.loyalty_type === 'stamps';
 72→  const maxStamps = merchant?.stamps_required ?? 10;
 73→  const currentStamps = card?.current_stamps ?? 0;
 74→  const currentPoints = card?.current_points ?? 0;
 75→  const rewardThreshold = merchant?.reward_threshold ?? 100;
 76→
 77→  if (loading) {
 78→    return (
 79→      <SafeAreaView style={styles.container}>
 80→        <Stack.Screen options={{ headerShown: true, title: 'Chargement...' }} />
 81→        <View style={styles.content}><SkeletonCard /><SkeletonCard /></View>
 82→      </SafeAreaView>
 83→    );
 84→  }
 85→
 86→  if (!card) {
 87→    return (
 88→      <SafeAreaView style={styles.container}>
 89→        <Stack.Screen options={{ headerShown: true, title: 'Carte introuvable' }} />
 90→        <View style={styles.content}>
 91→          <Text style={styles.errorText}>Cette carte n'existe pas ou a ete supprimee.</Text>
 92→        </View>
 93→      </SafeAreaView>
 94→    );
 95→  }
 96→
 97→  // QR data for merchant to scan (customer's unique ID)
 98→  const qrData = JSON.stringify({
 99→    type: 'customer',
100→    customer_id: user?.id,
101→    card_id: card.id,
102→  });
103→
104→  return (
105→    <SafeAreaView style={styles.container} edges={['top']}>
106→      <Stack.Screen
107→        options={{
108→          headerShown: true,
109→          title: merchant?.name ?? 'Carte',
110→          headerStyle: { backgroundColor: theme.colors.background },
111→          headerTintColor: theme.colors.text,
112→        }}
113→      />
114→      <ScrollView
115→        refreshControl={<RefreshControl refreshing={false} onRefresh={refresh} tintColor={theme.colors.primary} />}
116→        contentContainerStyle={styles.content}
117→      >
118→        {/* Progress */}
119→        <Card style={styles.progressCard}>
120→          {isStamps ? (
121→            <>
122→              <Text style={styles.progressTitle}>
123→                {currentStamps}/{maxStamps} tampons
124→              </Text>
125→              <StampsGridMobile current={currentStamps} max={maxStamps} />
126→            </>
127→          ) : (
128→            <>
129→              <Text style={styles.progressTitle}>
130→                {currentPoints}/{rewardThreshold} points
131→              </Text>
132→              <CircularProgress
133→                current={currentPoints}
134→                max={rewardThreshold}
135→                size={160}
136→                label={`${currentPoints} pts`}
137→              />
138→            </>
139→          )}
140→        </Card>
141→
142→        {/* QR Code for merchant to scan */}
143→        <Card style={styles.qrCard}>
144→          <Text style={styles.qrTitle}>Votre QR code client</Text>
145→          <Text style={styles.qrSubtitle}>Presentez-le au commercant</Text>
146→          <View style={styles.qrContainer}>
147→            <QRCode value={qrData} size={200} backgroundColor="#fff" color="#000" />
148→          </View>
149→        </Card>
150→
151→        {/* Rewards */}
152→        {rewards && rewards.length > 0 && (
153→          <Card>
154→            <Text style={styles.sectionTitle}>Recompenses</Text>
155→            {rewards.map((r) => (
156→              <View key={r.id} style={styles.rewardRow}>
157→                <Text style={{ flex: 1, fontSize: theme.fontSize.sm, color: theme.colors.text }}>
158→                  {r.description}
159→                </Text>
160→                <Badge variant={r.is_redeemed ? 'neutral' : 'success'}>
161→                  {r.is_redeemed ? 'Utilisee' : 'Disponible'}
162→                </Badge>
163→              </View>
164→            ))}
165→          </Card>
166→        )}
167→
168→        {/* Recent scans */}
169→        <Card>
170→          <Text style={styles.sectionTitle}>Historique des scans</Text>
171→          {!scans?.length ? (
172→            <Text style={styles.emptyText}>Aucun scan pour le moment</Text>
173→          ) : (
174→            scans.map((s) => (
175→              <View key={s.id} style={styles.scanRow}>
176→                <Text style={styles.scanDate}>
177→                  {new Date(s.created_at).toLocaleDateString('fr-FR')}
178→                </Text>
179→                <Text style={styles.scanDetail}>
180→                  {s.stamps_added ? `+${s.stamps_added} tampon(s)` : `+${s.points_added} pts`}
181→                </Text>
182→              </View>
183→            ))
184→          )}
185→        </Card>
186→      </ScrollView>
187→    </SafeAreaView>
188→  );
189→}
190→
191→const styles = StyleSheet.create({
192→  container: { flex: 1, backgroundColor: theme.colors.background },
193→  content: { padding: theme.spacing.lg, gap: theme.spacing.md, paddingBottom: 100 },
194→  progressCard: { alignItems: 'center', paddingVertical: theme.spacing.xl },
195→  progressTitle: { fontSize: theme.fontSize.lg, fontWeight: '700', color: theme.colors.text, marginBottom: theme.spacing.md },
196→  qrCard: { alignItems: 'center', paddingVertical: theme.spacing.xl },
197→  qrTitle: { fontSize: theme.fontSize.lg, fontWeight: '600', color: theme.colors.text },
198→  qrSubtitle: { fontSize: theme.fontSize.sm, color: theme.colors.textMuted, marginBottom: theme.spacing.md },
199→  qrContainer: { padding: theme.spacing.md, backgroundColor: '#fff', borderRadius: theme.borderRadius.lg },
200→  sectionTitle: { fontSize: theme.fontSize.base, fontWeight: '600', color: theme.colors.text, marginBottom: theme.spacing.sm },
201→  rewardRow: { flexDirection: 'row', alignItems: 'center', paddingVertical: theme.spacing.sm, borderBottomWidth: 1, borderBottomColor: theme.colors.border },
202→  emptyText: { fontSize: theme.fontSize.sm, color: theme.colors.textMuted, textAlign: 'center', paddingVertical: theme.spacing.md },
203→  scanRow: { flexDirection: 'row', justifyContent: 'space-between', paddingVertical: theme.spacing.sm, borderBottomWidth: 1, borderBottomColor: theme.colors.border },
204→  scanDate: { fontSize: theme.fontSize.sm, color: theme.colors.textMuted },
205→  scanDetail: { fontSize: theme.fontSize.sm, fontWeight: '600', color: theme.colors.primary },
206→  errorText: { fontSize: theme.fontSize.base, color: theme.colors.textMuted, textAlign: 'center', paddingVertical: theme.spacing.xl },
207→});
